import React, { useState, useEffect } from 'react';

interface Photo {
  id: number;
  src: string;
  caption: string;
  color: string;
  label: string;
}

const photos: Photo[] = [
  { id: 1, src: '/img/image1.png', caption: 'Ring Ceremony', color: 'from-rose-900 to-red-950', label: 'The Promise' },
  { id: 2, src: '/img/image2.png', caption: 'Mehendi Night', color: 'from-emerald-900 to-green-950', label: 'Henna Night' },
  { id: 3, src: '/img/image3.jpeg', caption: 'Haldi Ceremony', color: 'from-yellow-800 to-amber-950', label: 'Turmeric Glow' },
  { id: 4, src: '/img/image4.jpeg', caption: 'Temple Blessing', color: 'from-orange-900 to-red-950', label: 'Sacred Moments' },
  { id: 5, src: '/img/image5.jpeg', caption: 'Bridal Look', color: 'from-pink-900 to-rose-950', label: 'The Bride' },
];

const PhotoGallery: React.FC = () => {
  const [lightbox, setLightbox] = useState<Photo | null>(null);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth <= 768);
    check();
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);

  return (
    <section
      id="gallery"
      style={{
        minHeight: '100vh',
        background:
          'linear-gradient(180deg, #050205 0%, #1a0508 30%, #2a0810 60%, #1a0508 80%, #050205 100%)',
        padding: '60px 16px',
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>
        {/* Title */}
        <div style={{ textAlign: 'center', marginBottom: 40 }}>
          <div style={{ fontSize: 12, color: '#FFA07A', letterSpacing: '0.3em' }}>நினைவுகள்</div>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '2.5rem', color: '#FFD700', fontStyle: 'italic' }}>
            Our Gallery
          </h2>
        </div>

        {/* Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: 20,
          }}
        >
          {photos.map((photo, idx) => (
            <div
              key={photo.id}
              onClick={() => setLightbox(photo)}
              style={{
                aspectRatio: isMobile ? 'auto' : idx === 0 || idx === 4 ? '16/9' : '4/3',
                minHeight: isMobile ? 260 : undefined,
                background: `linear-gradient(145deg, ${getColor(photo.color)})`,
                borderRadius: 10,
                position: 'relative',
                overflow: 'hidden',
                cursor: 'pointer',
              }}
            >
              {/* Image */}
              <img
                src={photo.src}
                alt={photo.caption}
                style={{
                  width: '100%',
                  height: '100%',
                  objectFit: isMobile ? 'contain' : 'cover',
                  objectPosition: 'center',
                  backgroundColor: isMobile ? 'rgba(0,0,0,0.4)' : 'transparent',
                }}
              />

              {/* Overlay */}
              <div
                style={{
                  position: 'absolute',
                  inset: 0,
                  background:
                    'linear-gradient(180deg, transparent 45%, rgba(0,0,0,0.75) 100%)',
                }}
              />

              {/* Text */}
              <div style={{ position: 'absolute', bottom: 0, padding: 16 }}>
                <div style={{ color: '#FFD700', fontStyle: 'italic', fontSize: 18 }}>
                  {photo.label}
                </div>
                <div style={{ color: '#FFA07A', fontSize: 11, letterSpacing: '0.2em' }}>
                  {photo.caption.toUpperCase()}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox (already perfect for mobile) */}
      {lightbox && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.95)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
          }}
        >
          <img
            src={lightbox.src}
            alt={lightbox.caption}
            style={{
              maxWidth: '95vw',
              maxHeight: '90vh',
              objectFit: 'contain',
              borderRadius: 10,
            }}
          />
        </div>
      )}
    </section>
  );
};

function getColor(colorClass: string): string {
  const map: Record<string, string> = {
    'from-rose-900 to-red-950': '#4a0d1a, #2d0510',
    'from-emerald-900 to-green-950': '#064a25, #022d10',
    'from-yellow-800 to-amber-950': '#4a3006, #2d1a02',
    'from-orange-900 to-red-950': '#4a1e06, #2d0a02',
    'from-pink-900 to-rose-950': '#4a0d25, #2d0515',
  };
  return map[colorClass] || '#4a0d1a, #2d0510';
}

export default PhotoGallery;
